import React from "react";

interface PreloaderProps {
  isLoading: boolean;
}

export default function Preloader({ isLoading }: PreloaderProps) {
  return (
    <div
      aria-hidden={!isLoading}
      className={[
        "fixed inset-0 z-[9999] flex items-center justify-center bg-white",
        "transition-opacity duration-700 ease-in-out",
        isLoading ? "opacity-100" : "opacity-0 pointer-events-none",
      ].join(" ")}
    >
      <div className="flex flex-col items-center gap-4">
        <img
          src="data:image/png;base64,"
          alt="Cargando..."
          className="h-16 w-16 object-contain"
          onError={(e) => {
            // si el base64 está mal, mostramos un fallback visual
            (e.currentTarget as HTMLImageElement).style.display = "none";
          }}
        />

        {/* Fallback que siempre se ve */}
        <div className="h-2 w-72 overflow-hidden rounded-full bg-black/10">
  <div className="h-full rounded-full bg-black/60 animate-loaderBar" />
</div>


        <p className="text-sm text-black/60">Cargando…</p>
      </div>
    </div>
  );
}
